# Write development_lengths.csv
with open('config/development_lengths.csv', 'w', newline='') as f:
    w = csv.writer(f)
    w.writerow(['fy','diameter','fc','member_type','Ldb','Ldt','Ldh','Ldc'])
    for fy in [400,500,600]:
        for fc in [21,24,27,30,35,40]:
            d = data[fy][fc]
            for mt in member_types:
                for i, bar in enumerate(bars):
                    Ldb, Ldt = d[mt]['dev'][i]
                    w.writerow([fy, bar, fc, mt, Ldb, Ldt, d['Ldh'][i], d['Ldc'][i]])

# Write lap_splice.csv
with open('config/lap_splice.csv', 'w', newline='') as f:
    w = csv.writer(f)
    w.writerow(['fy','diameter','fc','member_type','Lpb','Lpt','Ldc','Lpc'])
    for fy in [400,500,600]:
        for fc in [21,24,27,30,35,40]:
            d = data[fy][fc]
            for mt in member_types:
                for i, bar in enumerate(bars):
                    Lpb, Lpt = d[mt]['lap'][i]
                    w.writerow([fy, bar, fc, mt, Lpb, Lpt, d['Ldc'][i], d['Lpc'][i]])

